#!/usr/bin/env python3
"""Extract the verbatim design-session conversation into a formatted .md
and a lossless .jsonl. User/assistant prose is rendered verbatim. Two
redactions for a PUBLIC repo: (1) harness-injected <system-reminder>
blocks are collapsed in the .md; (2) third-party PAID content fetched
from the Nate B. Jones Executive Circle MCP (the author's licensed
library) is redacted from BOTH files — our dialogue and our own research
syntheses are untouched; the substance lives, with attribution, in
research/01-prior-art.md."""
import json
import re
import sys

SRC = sys.argv[1]
OUT_MD = sys.argv[2]
OUT_JSONL = sys.argv[3]

SYSREMINDER = re.compile(r"<system-reminder>.*?</system-reminder>", re.DOTALL)
FOLD = 1600  # chars; tool results/inputs longer than this are folded in the .md

# Third-party paid content to redact (public repo). Redact by tool name
# (any Nate B. Jones MCP tool) with a content-signature fallback.
REDACT_TOOL_PREFIX = "mcp__claude_ai_Nate_B_Jones"
REDACT_SIGNATURES = (
    "Stop being the integration layer for your AIs",
    "Every Agent Needs One Owner",
    "Open Engine isn't another chatbot",
)
REDACTION = (
    "[third-party paid content redacted from this public repo — "
    "Nate B. Jones Executive Circle MCP result; the substance is "
    "captured with attribution in research/01-prior-art.md]"
)


def is_redacted_signature(text):
    return any(sig in text for sig in REDACT_SIGNATURES)


def render_text(t):
    return SYSREMINDER.sub("[system-reminder folded — see transcript.jsonl]", t)


def fold(text, label):
    if text is None:
        return ""
    if len(text) <= FOLD:
        return text
    head = text[:800].rstrip()
    return f"{head}\n\n…[folded — {len(text)} chars total; full content in transcript.jsonl ({label})]…"


# Pass 1: map tool_use_id -> tool name across the whole source.
tool_names = {}
raw_lines = []
with open(SRC, encoding="utf-8") as fh:
    for line in fh:
        line = line.strip()
        if not line:
            continue
        try:
            rec = json.loads(line)
        except json.JSONDecodeError:
            continue
        if rec.get("type") in ("user", "assistant"):
            raw_lines.append(rec)
            content = rec.get("message", {}).get("content")
            if isinstance(content, list):
                for block in content:
                    if isinstance(block, dict) and block.get("type") == "tool_use":
                        tool_names[block.get("id")] = block.get("name", "")


def tool_result_text(block):
    rc = block.get("content", "")
    if isinstance(rc, list):
        parts = []
        for c in rc:
            if isinstance(c, dict) and c.get("type") == "text":
                parts.append(c.get("text", ""))
            else:
                parts.append(json.dumps(c, ensure_ascii=False))
        rc = "\n".join(parts)
    return str(rc)


def should_redact(block):
    if block.get("type") != "tool_result":
        return False
    name = tool_names.get(block.get("tool_use_id"), "")
    if name.startswith(REDACT_TOOL_PREFIX):
        return True
    return is_redacted_signature(tool_result_text(block))


# Pass 2: emit redacted lossless .jsonl + readable .md
redacted_count = 0
out_jsonl = open(OUT_JSONL, "w", encoding="utf-8")
md = []
md.append("# Design session transcript — work-item state machine\n")
md.append(
    "Verbatim capture of the design/research/brainstorming session that "
    "produced this plan thread. User and assistant prose are verbatim; "
    "harness `<system-reminder>` blocks and large tool outputs are folded "
    "for readability (intact in `transcript.jsonl`). Third-party PAID "
    "content fetched from the Nate B. Jones Executive Circle MCP is "
    "REDACTED from both files (this is a public repo); its substance is "
    "captured, with attribution, in `../research/01-prior-art.md`. Snapshot "
    "captured during plan-capture; the final execution turns are not "
    "included — the design discussion is complete as captured.\n"
)

turn = 0
for rec in raw_lines:
    msg = rec.get("message", {})
    role = msg.get("role", rec.get("type"))
    content = msg.get("content")
    ts = rec.get("timestamp", "")
    turn += 1

    # redact in the record we serialize to jsonl
    if isinstance(content, list):
        for block in content:
            if isinstance(block, dict) and should_redact(block):
                block["content"] = REDACTION
                redacted_count += 1
    out_jsonl.write(json.dumps(rec, ensure_ascii=False) + "\n")

    header = "👤 User" if role == "user" else "🤖 Assistant"
    md.append(f"\n## {header} — turn {turn}  <sub>{ts}</sub>\n")
    if isinstance(content, str):
        md.append(render_text(content) + "\n")
        continue
    if isinstance(content, list):
        for block in content:
            if not isinstance(block, dict):
                md.append(str(block) + "\n")
                continue
            btype = block.get("type")
            if btype == "text":
                md.append(render_text(block.get("text", "")) + "\n")
            elif btype == "thinking":
                md.append("> _[assistant thinking folded — see transcript.jsonl]_\n")
            elif btype == "tool_use":
                name = block.get("name", "?")
                inp = json.dumps(block.get("input", {}), indent=2, ensure_ascii=False)
                md.append(f"\n**🔧 tool call → `{name}`**\n")
                md.append("```json\n" + fold(inp, f"tool_use {name}") + "\n```\n")
            elif btype == "tool_result":
                body = block["content"] if block.get("content") == REDACTION else tool_result_text(block)
                md.append("\n**📄 tool result**\n")
                md.append("```\n" + fold(str(body), "tool_result") + "\n```\n")
            else:
                md.append(f"\n**[{btype} block — see transcript.jsonl]**\n")
        continue
    md.append("\n")

out_jsonl.close()
with open(OUT_MD, "w", encoding="utf-8") as fh:
    fh.write("\n".join(md))

print(f"records={len(raw_lines)} redacted_blocks={redacted_count} md={OUT_MD} jsonl={OUT_JSONL}")

